Button:
[ M3e.button [ M3e.variantTonal ] [ M3e.slotIcon (M3e.icon [ M3e.attrName "send" ] []), Kit.text "Send" ]
    , M3e.button [ M3e.variantTonal ] [ M3e.slotTrailingIcon (M3e.icon [ M3e.attrName "open_in_new_window" ] []), Kit.text "Open" ]
    ]

[ M3e.button [ M3e.variantFilled, M3e.attrDisabled True ] [ Kit.text "Disabled" ]
    , M3e.button [ M3e.variantFilled, M3e.attrDisabledInteractive True ] [ Kit.text "Disabled Interactive" ]
    ]

Chips:
[ M3e.assistChip [] [ Kit.text "Outlined Assist" ]
    , M3e.assistChip [ M3e.variantElevated ] [ Kit.text "Elevated Assist" ]
    ]

[ M3e.assistChip [ M3e.attrDisabled True ] [ Kit.text "Disabled" ]
    , M3e.assistChip [ M3e.attrDisabledInteractive True ] [ Kit.text "Disabled Interactive" ]
    ]

[ M3e.suggestionChip [] [ Kit.text "Outlined Suggestion" ]
    , M3e.suggestionChip [ M3e.variantElevated ] [ Kit.text "Elevated Suggestion" ]
    ]

[ M3e.suggestionChip [ M3e.attrDisabled True ] [ Kit.text "Disabled" ]
    , M3e.suggestionChip [ M3e.attrDisabledInteractive True ] [ Kit.text "Disabled Interactive" ]
    ]

Fab:
[ M3e.fab [ M3e.attrDisabled True ] [ M3e.icon [ M3e.attrName "add" ] [] ]
    , M3e.fab [ M3e.attrDisabledInteractive True ] [ M3e.icon [ M3e.attrName "add" ] [] ]
    ]

IconButton:
[ M3e.iconButton [ M3e.variantTonal, M3e.widthNarrow ] [ M3e.icon [ M3e.attrName "add" ] [] ]
    , M3e.iconButton [ M3e.variantTonal, M3e.widthWide ] [ M3e.icon [ M3e.attrName "add" ] [] ]
    ]

[ M3e.iconButton [ M3e.variantFilled, M3e.attrDisabled True ] [ M3e.icon [ M3e.attrName "check" ] [] ]
    , M3e.iconButton [ M3e.variantFilled, M3e.attrDisabledInteractive True ] [ M3e.icon [ M3e.attrName "check" ] [] ]
    ]

Switch:
[ M3e.switch [ M3e.iconsSelected, M3e.attrChecked True ] []
    , M3e.switch [ M3e.iconsBoth ] []
    ]

Theme:
[ M3e.theme [ M3e.attrStrongFocus True, M3e.motionStandard ] [ Native.node Html.label [] [ Kit.text "Standard", M3e.switch [] [] ] ]
    , M3e.theme [ M3e.attrStrongFocus True, M3e.motionExpressive ] [ Native.node Html.label [] [ Kit.text "Expressive", M3e.switch [] [] ] ]
    ]

Toolbar:
[ M3e.toolbar [ M3e.variantStandard ] [ M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_back" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_forward" ] [] ], M3e.iconButton [ M3e.widthWide, M3e.variantFilled ] [ M3e.icon [ M3e.attrName "add" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "picture_in_picture" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "more_vert" ] [] ] ]
    , M3e.toolbar [ M3e.variantVibrant ] [ M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_back" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_forward" ] [] ], M3e.iconButton [ M3e.widthWide, M3e.variantFilled ] [ M3e.icon [ M3e.attrName "add" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "picture_in_picture" ] [] ], M3e.iconButton [] [ M3e.icon [ M3e.attrName "more_vert" ] [] ] ]
    ]

Tooltip:
[ M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_back" ] [] ]
    , M3e.tooltip [ M3e.attrFor "button" ] [ Kit.text "Go Back" ]
    ]

[ M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_back" ] [] ]
    , M3e.tooltip [ M3e.attrFor "button", M3e.attrShowDelay 0, M3e.attrHideDelay 200 ] [ Kit.text "Go Back" ]
    ]

[ M3e.iconButton [] [ M3e.icon [ M3e.attrName "arrow_back" ] [] ]
    , M3e.tooltip [ M3e.attrFor "button", M3e.attrDisabled True ] [ Kit.text "Go Back" ]
    ]
